diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..3715ccdb151d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2667,6 +2667,81 @@ foldRoundUpIntegerWithPow2Alignment(SelectInst &SI,
   Value *R = Builder.CreateAnd(XOffset, ConstantInt::get(Ty, *HighBitMaskCst));
   R->takeName(&SI);
   return R;
+  llvm::errs() << "PATCH_HIT\\n";
+}
+
+/// Look for patterns like
+///   %outer.cond = select i1 %inner.cond, i1 %alt.cond, i1 false
+///   %inner.sel = select i1 %inner.cond, i8 %inner.sel.t, i8 %inner.sel.f
+///   %outer.sel = select i1 %outer.cond, i8 %outer.sel.t, i8 %inner.sel
+/// and rewrite it as
+///   %inner.sel = select i1 %cond.alternative, i8 %sel.outer.t, i8 %sel.inner.t
+///   %sel.outer = select i1 %cond.inner, i8 %inner.sel, i8 %sel.inner.f
+static Instruction *foldNestedSelects(SelectInst &OuterSel,
+                                      InstCombiner::BuilderTy &Builder) {
+  // We must start with a `select`.
+  Value *OuterCond, *InnerSel, *OuterSelFalseVal;
+  match(&OuterSel, m_Select(m_Value(OuterCond), m_Value(InnerSel),
+                            m_Value(OuterSelFalseVal)));
+
+  // Canonicalize inversion of the outermost `select`'s condition.
+  if (match(OuterCond, m_Not(m_Value(OuterCond))))
+    std::swap(InnerSel, OuterSelFalseVal);
+
+  auto m_c_LogicalOp = [](auto L, auto R) {
+    return m_CombineOr(m_c_LogicalAnd(L, R), m_c_LogicalOr(L, R));
+  };
+
+  // The condition of the outermost select must be an `and`/`or`.
+  if (!match(OuterCond, m_c_LogicalOp(m_Value(), m_Value())))
+    return nullptr;
+
+  // To simplify logic, prefer the pattern variant with an `or`.
+  bool IsAndVariant = match(OuterCond, m_LogicalAnd());
+  if (match(OuterCond, m_LogicalAnd()))
+    std::swap(InnerSel, OuterSelFalseVal);
+
+  // Profitability check - avoid increasing instruction count.
+  if (none_of(ArrayRef<Value *>({OuterCond, InnerSel}),
+              [](Value *V) { return V->hasOneUse(); }))
+    return nullptr;
+
+  // The appropriate hand of the outermost `select` must be a select itself.
+  Value *InnerCond, *InnerSelTrueVal, *InnerSelFalseVal;
+  if (!match(InnerSel, m_Select(m_Value(InnerCond), m_Value(InnerSelTrueVal),
+                                m_Value(InnerSelFalseVal))))
+    return nullptr;
+
+  // Canonicalize inversion of the innermost `select`'s condition.
+  if (match(InnerCond, m_Not(m_Value(InnerCond))))
+    std::swap(InnerSelTrueVal, InnerSelFalseVal);
+
+  Value *AltCond = nullptr;
+  auto matchOuterCond = [OuterCond, m_c_LogicalOp, &AltCond](auto m_InnerCond) {
+    return match(OuterCond, m_c_LogicalOp(m_InnerCond, m_Value(AltCond)));
+  };
+
+  // Finally, match the condition that was driving the outermost `select`,
+  // it should be a logical operation between the condition that was driving
+  // the innermost `select` (after accounting for the possible inversions
+  // of the condition), and some other condition.
+  if (matchOuterCond(m_Specific(InnerCond))) {
+    // Done!
+  } else if (Value * NotInnerCond; matchOuterCond(m_CombineAnd(
+                 m_Not(m_Specific(InnerCond)), m_Value(NotInnerCond)))) {
+    // Done!
+    std::swap(InnerSelTrueVal, InnerSelFalseVal);
+    InnerCond = NotInnerCond;
+  } else // Not the pattern we were looking for.
+    return nullptr;
+
+  Value *SelInner = Builder.CreateSelect(
+      AltCond, IsAndVariant ? OuterSelFalseVal : InnerSelFalseVal,
+      IsAndVariant ? InnerSelTrueVal : OuterSelFalseVal);
+  SelInner->takeName(InnerSel);
+  return SelectInst::Create(InnerCond,
+                            IsAndVariant ? SelInner : InnerSelTrueVal,
+                            IsAndVariant ? InnerSelFalseVal : SelInner);
 }

 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
@@ -2843,56 +2918,77 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       return SelectInst::Create(C, A, B);
     }

-    // (!C && A) || (C && B) --> sel C, B, A
-    // (A && !C) || (C && B) --> sel C, B, A
-    // (!C && A) || (B && C) --> sel C, B, A
-    // (A && !C) || (B && C) --> sel C, B, A (may require freeze)
-    if (match(CondVal, m_c_LogicalAnd(m_Not(m_Value(C)), m_Value(A))) &&
-        match(FalseVal, m_c_LogicalAnd(m_Specific(C), m_Value(B)))) {
-      auto *SelCond = dyn_cast<SelectInst>(CondVal);
-      auto *SelFVal = dyn_cast<SelectInst>(FalseVal);
-      bool MayNeedFreeze = SelCond && SelFVal &&
-                           match(SelCond->getTrueValue(),
-                                 m_Not(m_Specific(SelFVal->getTrueValue())));
-      if (MayNeedFreeze)
-        C = Builder.CreateFreeze(C);
-      return SelectInst::Create(C, B, A);
+  // select (select X, Y, false), Z, (select X, W, V) -> select X, (select Y, Z, W), V
+  // select (select X, true, Y), (select X, W, V), Z -> select X, W, (select Y, V, Z)
+  // Also handles cases where X is inverted in one of the selects.
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    // Match outer condition as logical AND (select X, Y, false) or
+    // logical OR (select X, true, Y).
+    Value *XCond = CondSI->getCondition();
+    Value *Y = CondSI->getTrueValue();
+    Value *CondFalse = CondSI->getFalseValue();
+
+    bool IsAnd = match(CondFalse, m_Zero()) && Y->getType() == CondVal->getType();
+    bool IsOr = match(Y, m_One()) && CondFalse->getType() == CondVal->getType();
+
+    if (IsAnd || IsOr) {
+      Value *AltCond = IsAnd ? Y : CondFalse;
+
+      // Check if a value is a select with condition X or not X.
+      auto MatchInnerSelect = [&](Value *V, Value *&XSel,
+                                   Value *&W, Value *&VInner) -> bool {
+        auto *SI = dyn_cast<SelectInst>(V);
+        if (!SI)
+          return false;
+        Value *Cond = SI->getCondition();
+        // Check if Cond equals XCond or is the NOT of XCond.
+        if (Cond == XCond) {
+          XSel = XCond;
+        } else {
+          Value *NotX;
+          if (match(Cond, m_Not(m_Value(NotX))) && NotX == XCond)
+            XSel = Cond; // XSel is the actual condition used (not XCond)
+          else if (match(XCond, m_Not(m_Value(NotX))) && NotX == Cond)
+            XSel = XCond; // XCond is not of Cond
+          else
+            return false;
+        }
+        // Only fold if at least one of the inner selects will be eliminated.
+        if (!CondSI->hasOneUse() && !SI->hasOneUse())
+          return false;
+        W = SI->getTrueValue();
+        VInner = SI->getFalseValue();
+        return true;
+      };
+
+      Value *XSel, *W, *V;
+      if (IsAnd) {
+        // select (select X1, Y, false), Z, (select X2, W, V)
+        if (MatchInnerSelect(FalseVal, XSel, W, V)) {
+          Value *InnerSel = Builder.CreateSelect(AltCond, TrueVal, W);
+          return SelectInst::Create(XSel, InnerSel, V);
+        }
+        // select (select X1, Y, false), (select X2, W, V), Z
+        if (MatchInnerSelect(TrueVal, XSel, W, V)) {
+          Value *InnerSel = Builder.CreateSelect(AltCond, W, FalseVal);
+          return SelectInst::Create(XSel, InnerSel, FalseVal);
+        }
+      }
+      if (IsOr) {
+        // select (select X1, true, Y), (select X2, W, V), Z
+        if (MatchInnerSelect(TrueVal, XSel, W, V)) {
+          Value *InnerSel = Builder.CreateSelect(AltCond, V, FalseVal);
+          return SelectInst::Create(XSel, W, InnerSel);
+        }
+        // select (select X1, true, Y), Z, (select X2, W, V)
+        if (MatchInnerSelect(FalseVal, XSel, W, V)) {
+          Value *InnerSel = Builder.CreateSelect(AltCond, TrueVal, V);
+          return SelectInst::Create(XSel, TrueVal, InnerSel);
+        }
+      }
     }
   }

-  return nullptr;
-}
-
-Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
-  Value *CondVal = SI.getCondition();
-  Value *TrueVal = SI.getTrueValue();
-  Value *FalseVal = SI.getFalseValue();
-  Type *SelType = SI.getType();
-
-  if (Value *V = simplifySelectInst(CondVal, TrueVal, FalseVal,
-                                    SQ.getWithInstruction(&SI)))
-    return replaceInstUsesWith(SI, V);
-
-  if (Instruction *I = canonicalizeSelectToShuffle(SI))
-    return I;
-
-  if (Instruction *I = canonicalizeScalarSelectOfVecs(SI, *this))
-    return I;
-
-  // If the type of select is not an integer type or if the condition and
-  // the selection type are not both scalar nor both vector types, there is no
-  // point in attempting to match these patterns.
-  Type *CondType = CondVal->getType();
-  if (!isa<Constant>(CondVal) && SelType->isIntOrIntVectorTy() &&
-      CondType->isVectorTy() == SelType->isVectorTy()) {
-    if (Value *S = simplifyWithOpReplaced(TrueVal, CondVal,
-                                          ConstantInt::getTrue(CondType), SQ,
-                                          /* AllowRefinement */ true))
-      return replaceOperand(SI, 1, S);
-
-    if (Value *S = simplifyWithOpReplaced(FalseVal, CondVal,
-                                          ConstantInt::getFalse(CondType), SQ,
-                                          /* AllowRefinement */ true))
       return replaceOperand(SI, 2, S);

     // Handle patterns involving sext/zext + not explicitly,
@@ -3292,5 +3388,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  if (Instruction *I = foldNestedSelects(SI, Builder))
+    return I;
+
   return nullptr;
+  llvm::errs() << "PATCH_HIT\\n";
 }

